public interface IPaymentGateway {
  bool Charge(decimal amount);
}

public class LegacyGateway {
  public int MakePayment(double amount) => 1;
}

public class PaymentGatewayAdapter : IPaymentGateway {
  private readonly LegacyGateway _legacy;
  public PaymentGatewayAdapter(LegacyGateway legacy) { _legacy = legacy; }

  public bool Charge(decimal amount) {
    return _legacy.MakePayment((double)amount) == 1;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Charge_ReturnsTrue_WhenLegacySucceeds() {
  var gateway = new PaymentGatewayAdapter(new LegacyGateway());
  Assert.IsTrue(gateway.Charge(12.50m));
}

[TestMethod]
public void Adapter_ImplementsTargetInterface() {
  IPaymentGateway gateway = new PaymentGatewayAdapter(new LegacyGateway());
  Assert.IsNotNull(gateway);
}
